//
import { SERIES_LEGEND_CLASSNAME, LEGSERIES_LEGEND_CLASSNAME } from '../../legend-constants';
import { Registry } from '../../../core/zc-registry';
import { validateNullVal } from '../../../utils/zcutils';
import { getBoxSize } from '../../../view/list/list-parser';
import { expandableState } from '../../expandable/expandable-parser';

/**
 *
 * @param chart
 * @return {Legend Event options}
 */
function _legendDiscreteEventArguments(chart, id) {
    let legendInstance = chart.legends.get(id),
        { component, element, meta, highlightManager } = legendInstance,
        { config, globalFont, scaleComponent } = meta,
        { events: eventsConfig } = config,
        { dataType } = scaleComponent.schema.data,
        //
        trackerElement = getTrackerElement(element),
        { ticks, scale } = component.viewScaleComponent(),
        //
        eventDisabled = eventsConfig && validateNullVal(eventsConfig.enabled, true) == false,
        enabled = legendInstance.enabled && !eventDisabled,
        //
        scrollToItem,
        boxSize;

    if (enabled) {
        let viewSpec = component._parser.viewSpec,
            { list: listConfig } = viewSpec.config,
            { marker: markerConfig, label: labelConfig } = listConfig;
        boxSize = getBoxSize(markerConfig, labelConfig, viewSpec.align, viewSpec.scale, viewSpec.label.fontSize);

        scrollToItem = getScrollToItem(element, component);
    }
    var legendOptions = config,
        colorbandOptions = legendOptions.colorBand,
        isDiscrete = colorbandOptions.ranges && colorbandOptions.ranges.length;

    return { enabled, trackerElement, highlightManager, config, globalFont, dataType, legendInstance, scale, ticks, boxSize, scrollToItem, isDiscrete: true, data: meta.data };
}

/**
 * Returns tracker element
 * @param  {D3Selectiion} container
 * @return {D3Selectiion}
 */
function getTrackerElement(container) {
    return container.selectAll(`li.${SERIES_LEGEND_CLASSNAME}`);
}

function getScrollToItem(container, component) {
    let ulElement = container && container.selectAll(`.${LEGSERIES_LEGEND_CLASSNAME}`).node();

    if (ulElement) {
        let expandableMark = component.encode.children[2], // TODO: work
            liElement = ulElement ? ulElement.children : [],
            parser = expandableMark._parser, // TODO: work
            _expanded = parser.show ? expandableState(expandableMark) : true,
            { isHorizontal } = expandableMark._spec, // TODO: work
            measure = isHorizontal ? 'Width' : 'Height';

        return {
            ulElement,
            liElement,
            available: ulElement[`client${measure}`],
            isScrollable: ulElement[`scroll${measure}`] > ulElement[`client${measure}`] && _expanded,
            isHorizontal
        };
    }
}

export { _legendDiscreteEventArguments };
Registry.setComponent('_legendDiscreteEventArguments', _legendDiscreteEventArguments);
